INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6f0ba476-moex-00542', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司為製造工業用材料的化學公司，因不慎排放廢水污染到工廠附近的下水道，引起當地 居民的抗議並提起訴訟要求賠償。由於已經被環保單位認定為有潛在責任的一方，甲公司的 管理當局與法律顧問評估此案件很有可能要賠償相關損害。經法律顧問的評估，訴訟判決損 害賠償的金額可能介於$2,000,000至$5,000,000間，再根據過去的判決案例，法律顧問認為最 有可能的賠償金額為$4,000,000。請問甲公司除附註揭露該事項及可能損失外，應在資產負債 表中認列之負債準備為何？', '["$2,000,000", "$3,500,000", "$4,000,000", "$5,000,000 32470"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00543', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司X1年12月31日流通在外普通股股數750,000股。於X2年7月1日現金增資發行450,000 股（無紅利因子）。甲公司於X2年初亦有股票選擇權流通在外，持有人得以每股$25購買300,000 股普通股，此股票選擇權於 X2 年底並未被執行。假設甲公司 X2 年全年度普通股平均市價為 $32，試問甲公司於計算X2年稀釋每股盈餘所使用之加權平均流通在外股數為：', '["975,000", "1,040,625", "1,209,375", "1,275,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00544', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '下列有關於投資性不動產之會計處理，何者錯誤？', '["投資性不動產購入時，應以成本衡量", "目前尚未確定將來用途的土地，屬於投資性不動產", "投資性不動產認列後選用公允價值模式衡量，不得改為成本模式", "企業將不動產出租給母公司或其他子公司，在編製合併報表時，該不動產應列為投資性不 動產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00545', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '乙公司X3年期初現金餘額與期末現金餘額分別為$175,000與$205,000，X3年度投資活動現 金淨流入$300,000，籌資活動現金淨流出$420,000，折舊費用$37,000，出售設備利益$5,000， 應收帳款減少數$48,000，存貨增加數$12,000，應付帳款增加數$30,000，應付所得稅減少數 $7,000，支付所得稅$85,000。若乙公司將所得稅歸類於營業活動，請問乙公司 X3 年度本期 淨利為何？', '["$85,000", "$137,000", "$59,000", "$104,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00546', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司成立於X1年年初，核准發行面額$10之普通股800,000股。X1年12月31日的資產 負債表顯示，普通股股本為$4,000,000、普通股發行溢價為$2,400,000與保留盈餘為$800,000。 X2年9月1日，甲公司以每股$15收回庫藏股票30,000股，後續兩次出售該批庫藏股票分別 於X2年11月1日以每股$10出售12,000股與X2年12月1日以每股$17出售6,000股。X2 年 12 月 31 日的資產負債表顯示保留盈餘為$1,250,250。若甲公司保留盈餘之變動除前述交 易之可能影響外均來自淨利，請問X1年度與X2年度甲公司的每股盈餘為何？（答案四捨五 入至小數點後一位）', '["$1與$1.5", "$2與$1.3", "$1與$1.3", "$2與$1.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00547', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '乙公司X4年度銷貨總額為$2,000,000，其中70%為現金銷貨。乙公司X4年12月31日調整 前應收帳款之總帳面金額為$480,000，備抵損失為貸餘$20,000。X4年12月31日應收帳款的 帳齡分析如下： 帳 齡 金 額 估計可收回之比率 15天以內 $260,000 0.96 16～30天 80,000 0.92 31～45天 65,000 0.88 46～60天 ？ 0.78 61～90天 22,000 0.52 超過90天 20,000 0.00 $480,000 乙公司X4年12月31日應收帳款之攤銷後成本金額為何？', '["$417,580", "$437,580", "$460,000", "$480,000 32470"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00548', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司有X、Y、Z三個現金產生單位，並有一總部大樓為X、Y、Z三個現金產生單位之共 用資產，相關資料如下： X Y Z 總部大樓 帳面金額 $2,000,000 $5,000,000 $10,000,000 $5,000,000 耐用年限 5年 12年 25年 25年 可回收金額 $2,000,000 $6,000,000 $12,000,000 — 甲公司將X、Y、Z三個現金產生單位的帳面金額，依耐用年限加權後之相對比例作為分攤總部 大樓帳面金額之合理基礎，試問總部大樓應分攤減損損失金額是多少？（答案四捨五入至元）', '["$149,456", "$352,099", "$455,567", "$546,786"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00549', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初以每股$120的價格發行不可轉換、不可贖回的累積、參加特別股20,000股， 每股面額$100。特別股發行章程規定每年支付 2%股利；而若普通股股東每股獲分配$5 之股 利後尚有剩餘之待分配股利，該剩餘部分由普通股與特別股股東依照2：1之比例分配。已知 甲公司X1年度稅後淨利為$800,000，普通股全年流通在外股數為100,000股，請問該公司X1 年度普通股基本每股盈餘為多少？', '["$6.68", "$6.73", "$7.52", "$7.56"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00550', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日買入面額$100,000，X5年12月31日到期的公司債，票面利率4%， 每年 12 月 31 日付息，有效利率 5%，甲公司將此債務工具分類為按攤銷後成本衡量之金融 資產，該債務工具非信用減損之金融資產。X1年12月31日收到利息$4,000，經判斷自原始 認列後該債務工具之信用風險已顯著增加，當日存續期間預期信用損失金額為$9,000，12個 月預期信用損失金額為$3,000。若甲公司原始認列時將此債務工具分類為透過其他綜合損益 按公允價值衡量之金融資產，且X1年12月31日的市場利率為4%，則二種會計處理對X1 年底權益影響之差異為何？（不考慮所得稅之影響，四捨五入取至元）', '["$0", "$3,545", "$9,000", "$12,545"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00551', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年12月31日持有透過損益按公允價值衡量債券投資，該債券面額$800,000，票 面利率4%，其評價調整為利益$43,338，故帳面金額為$843,338。每年6月30日及12月31 日各付息一次。X1年12月31日甲公司決定改變其債券投資的經營模式。X2年1月1日該 債券的公允價值為$843,338（當日有效利率為3%），預期信用備抵損失為$6,400。X2年12月 31日，該債券的公允價值為$838,000，當日該債券並未達減損的地步，預期信用備抵損失估 計金額為$7,000。試問，下列敘述何者正確？', '["若甲公司將經營模式變更為只收取利息本金為目的，相較於變更為同時收取利息本金及出 售為目的，重分類分錄對權益之影響相同", "若甲公司將經營模式變更為同時收取利息本金及出售為目的，相較於變更為只收取利息本 金為目的，X2年度淨利相對較高$1,412", "若甲公司將經營模式變更為同時收取利息本金及出售為目的，相較於未變更下，X2年底權 益將減少$7,000", "若甲公司將經營模式變更為只收取利息本金為目的，相較於未變更下，X2 年底權益將 減少$8,412"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
